		setProof(replacement, LmdbRewriteProof.RewriteKind.ELIGIBILITY_UNION_SEMI_FILTER,
				LmdbRewriteProof.EquivalenceScope.EXISTENCE_EQUIVALENT,
				Set.of("correlation=" + String.join("|", correlationVars(base, union))),
				"union branch locals are dead and aggregates ignore eligibility multiplicity");
