	private static boolean canCollapseUnion(TupleExpr base, Union union, Group group) {
		Set<String> baseVars = base.getBindingNames();
		Set<String> corrVars = correlationVars(base, union);
		if (corrVars.isEmpty() || !base.getAssuredBindingNames().containsAll(corrVars)) {
			return false;
		}
		Set<String> branchLocals = new HashSet<>(union.getBindingNames());
		branchLocals.removeAll(baseVars);
		if (!group.getGroupBindingNames().stream().allMatch(baseVars::contains)) {
			return false;
		}
		if (group.getGroupElements()
				.stream()
				.anyMatch(element -> VarNameCollector.process(element).stream().anyMatch(branchLocals::contains))) {
			return false;
		}
		if (!group.getGroupElements()
				.stream()
				.allMatch(element -> aggregateInsensitive(element.getOperator(), baseVars))) {
			return false;
		}
		return LmdbTupleExprFacts.allUnionBranches(union)
				.stream()
				.allMatch(branch -> branch.getAssuredBindingNames().containsAll(corrVars)
						&& eligibilitySafe(branch));
	}

	private static Set<String> correlationVars(TupleExpr base, Union union) {
		Set<String> corrVars = new LinkedHashSet<>(union.getBindingNames());
		corrVars.retainAll(base.getBindingNames());
		return corrVars;
	}

	private static boolean aggregateInsensitive(AggregateOperator operator, Set<String> preservedVars) {
		if (operator instanceof Count count) {
			return count.isDistinct() && count.getArg()instanceof Var var && !var.hasValue()
					&& preservedVars.contains(var.getName());
		}
		if (operator instanceof Min || operator instanceof Max) {
			ValueExpr arg = ((AbstractAggregateOperator) operator).getArg();
			return arg != null && VarNameCollector.process(arg).stream().allMatch(preservedVars::contains);
		}
		return false;
	}

	private static boolean eligibilitySafe(TupleExpr tupleExpr) {
		if (tupleExpr instanceof StatementPattern || tupleExpr instanceof SingletonSet) {
			return true;
		}
		if (tupleExpr instanceof Union union) {
			return eligibilitySafe(union.getLeftArg()) && eligibilitySafe(union.getRightArg());
		}
		if (tupleExpr instanceof Join join) {
			return eligibilitySafe(join.getLeftArg()) && eligibilitySafe(join.getRightArg());
		}
		if (tupleExpr instanceof Filter filter) {
			return filter.getArg().getAssuredBindingNames().containsAll(VarNameCollector.process(filter.getCondition()))
					&& eligibilitySafe(filter.getArg());
		}
		if (tupleExpr instanceof LeftJoin || tupleExpr instanceof Difference || tupleExpr instanceof Service
				|| tupleExpr instanceof BindingSetAssignment || tupleExpr instanceof Extension) {
			return false;
		}
		return false;
	}

	private static void liftExistsAboveGroup(Group group) {
		if (!(group.getArg()instanceof Filter filter)) {
			return;
		}
		List<ValueExpr> conjuncts = LmdbTupleExprFacts.splitAnd(filter.getCondition());
		List<ValueExpr> retained = new ArrayList<>(conjuncts.size());
		List<ValueExpr> lifted = new ArrayList<>();
		for (ValueExpr conjunct : conjuncts) {
			if (conjunct instanceof Exists exists && existsCorrelatesOnlyOnGroupKeys(exists, filter.getArg(), group)) {
				lifted.add(conjunct);
			} else {
				retained.add(conjunct);
			}
		}
		if (lifted.isEmpty() || group.getParentNode() == null) {
			return;
		}
		if (retained.isEmpty()) {
			group.setArg(filter.getArg());
		} else {
			filter.setCondition(LmdbTupleExprFacts.combineAnd(retained));
		}
		Filter outer = new Filter();
		group.replaceWith(outer);
		outer.setArg(group);
		outer.setCondition(LmdbTupleExprFacts.combineAnd(lifted));
		setProof(outer, LmdbRewriteProof.RewriteKind.GROUP_KEY_EXISTS_LIFT,
				LmdbRewriteProof.EquivalenceScope.LOGICAL_BAG_EQUIVALENT,
				Set.of("groupKeys=" + String.join("|", group.getGroupBindingNames())),
				"exists correlation is constant per group");
	}

	private static boolean existsCorrelatesOnlyOnGroupKeys(Exists exists, TupleExpr input, Group group) {
		Set<String> corrVars = new LinkedHashSet<>(VarNameCollector.process(exists.getSubQuery()));
		corrVars.retainAll(input.getBindingNames());
		return group.getGroupBindingNames().containsAll(corrVars);
	}

	private static boolean sameAggregate(Count left, Count right) {
		return left.isDistinct() == right.isDistinct()
				&& String.valueOf(left.getArg()).equals(String.valueOf(right.getArg()));
	}

	private static void removeExtensionElem(Extension extension, ExtensionElem element) {
		if (extension.getElements().size() == 1) {
			extension.replaceWith(extension.getArg());
		} else {
			extension.getElements().remove(element);
		}
	}

	private static void setProof(QueryModelNode node, LmdbRewriteProof.RewriteKind kind,
			LmdbRewriteProof.EquivalenceScope scope, Set<String> facts, String reason) {
		LmdbRewriteProof proof = new LmdbRewriteProof(kind, scope, facts, reason);
		String existing = node.getStringMetricPlanned(PROOF_METRIC);
		if (existing == null || existing.isEmpty()) {
			node.setStringMetricPlanned(PROOF_METRIC, proof.metricFragment());
		} else {
			node.setStringMetricPlanned(PROOF_METRIC, existing + " || " + proof.metricFragment());
		}
	}

